	attempt := func(ctx context.Context) (*Result, error) {
		return &Result{Stderr: "rate limit exceeded"}, nil
	}
	_, err := RunWithRateLimitRetry(context.Background(), cfg, attempt)
	if err == nil {
		t.Fatal("expected error from cancelled sleep")
	}
}

